/*
 * Generates src/agents/prompts.bundle.ts by embedding the prompt files the
 * agents load (master / discipline / council / self-check). This lets the
 * PromptLoader work in the Convex runtime, which can't read arbitrary repo
 * files. The generated file is a gitignored build artifact, not hand-authored —
 * the canonical prompts remain in verifiq-prompts/. Run: npm run bundle:prompts
 *
 * Canonical per ADR-001: ONE bundle file (src/agents/prompts.bundle.ts), ONE
 * export (PROMPT_BUNDLE), gitignored and regenerated by this script. Do not add
 * a second bundle artifact.
 */
import { readFileSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const root = join(dirname(fileURLToPath(import.meta.url)), "..");
const FILES = [
  "01_master_system_prompt.md",
  "04_agent_prompts.md",
  "07_council_prompts.md",
  "13_agent_self_check_protocol.md",
];

const entries = FILES.map(
  (f) => `  ${JSON.stringify(f)}: ${JSON.stringify(readFileSync(join(root, "verifiq-prompts", f), "utf8"))},`,
).join("\n");

const out =
  `/* AUTO-GENERATED by scripts/bundle-prompts.mjs — do not edit. Run \`npm run bundle:prompts\`. */\n` +
  `/* eslint-disable */\n` +
  `export const PROMPT_BUNDLE: Record<string, string> = {\n${entries}\n};\n`;

writeFileSync(join(root, "src/agents/prompts.bundle.ts"), out);
console.log(`Bundled ${FILES.length} prompt files → src/agents/prompts.bundle.ts`);
